
import { useTranslation } from "react-i18next";
import { StaticImage } from "gatsby-plugin-image";
import React from "react";

const LanguageSelector = () => {

  const { i18n } = useTranslation();

  const changeLang = (lang) => {
    // Client-side language switching (no URL prefix)
    i18n.changeLanguage(lang);
    localStorage.setItem("selectedLang", lang);
  };

  return (

    <section className = "cursor-pointer z-[99] w-full gap-4 left-0 space-evenly h-auto flex flex-col tb:absolute transform scale-75 xsm:scale-35 tb:top-0 languageSelector">
      <span className = "animation_key_languaje flex flex-col items-center m-2 pt-1 cursor-pointer">
        <button id="btn_default"
          onClick={() => changeLang("es")}
          className="flex flex-col items-center m-2 p-3 cursor-pointer hover:border-0 hover:bg-[#007f0d44] rounded-xl border border-[#994743] bg-gray-400/90 transition shadow-md hover:scale-105"
        >
          <StaticImage
            src="../../assets/images/page1/colombia.webp"
            alt="Colombia"
            className="w-[2.7rem] h-[2.7rem] rounded-full cursor-pointer object-cover pointer-events-none"
            layout="constrained"
            placeholder="dominantColor"
          />
          <span className="mt-2 xsm:text-[2rem] text-55  text-base p-0.5 font-bold text-[#994743]">Español</span>
        </button>
      </span>

      <span className="flex animation_key_languaje2 flex-col items-center m-2 pt-1 cursor-pointer">   
        <button
          onClick={() => changeLang("pt")}
          className="flex flex-col items-center m-2 p-3 cursor-pointer hover:border-0 hover:bg-[#007f0d44] rounded-xl border border-[#994743] bg-gray-400/90 transition shadow-md hover:scale-105"
        >
          <StaticImage
            src="../../assets/images/page1/Brazil.webp"
            alt="Brazil"
            className="w-[2.7rem] h-[2.7rem] rounded-full cursor-pointer object-cover pointer-events-none"
            layout="constrained"
            placeholder="dominantColor"
          />
          <span className="mt-2 text-base p-0.5 font-bold text-[#994743]">Português</span>
        </button>
      </span>

      <span className="flex flex-col animation_key_languaje items-center m-2 pt-1 cursor-pointer">   
        <button
          onClick={() => changeLang("en")}
          className="flex flex-col items-center m-2 p-3 cursor-pointer hover:border-0 hover:bg-[#007f0d44] rounded-xl border border-[#994743] bg-gray-400/90 transition shadow-md hover:scale-105"
        >
          <StaticImage
            src="../../assets/images/page1/usa.webp"
            alt="USA"
            className="w-[2.7rem] h-[2.7rem] rounded-full cursor-pointer object-cover pointer-events-none"
            layout="constrained"
            placeholder="dominantColor"
          />
          <span className="mt-2 text-base p-0.5 font-bold text-[#994743]">English</span>
        </button>
      </span>
    </section>
  );
};

export default LanguageSelector;
