import React, { useRef, useEffect, useState } from 'react';
import { useTranslation } from "react-i18next";

const Heropage_features = () => {

  const { t } = useTranslation();
  const sectionRef = useRef(null);
  const [isVisible, setIsVisible] = useState(false);

  useEffect(() => {
    if (typeof window === "undefined" || !sectionRef.current) return;

    const observer = new IntersectionObserver(
      ([entry]) => {
        if (entry.isIntersecting) {
          setIsVisible(true);
          observer.disconnect();
        }
      },
      { threshold: 0.15 }
    );

    observer.observe(sectionRef.current);
    return () => observer.disconnect();
  }, []);

  return (
    <>
      <div
        ref={sectionRef}
        className="relative w-full border-gold border-2 min-h-screen flex flex-col items-start justify- py-16 bg-[url('../../assets/images/page2/Background-Image-cigar-Brevas.webp')] bg-cover md:bg-contain bg-no-repeat bg-center overflow-hidden"
        style={{
          opacity: isVisible ? 1 : 0,
          transform: `translateY(${isVisible ? 0 : 2}rem)`,
          transition: 'opacity 1s ease-out, transform 1s ease-out',
        }}
      >
        {/* Soft background dark overlay to increase contrast on large monitors */}
        <div className="absolute inset-0 bg-black/15 pointer-events-none"></div>

        {/* Frosted glass container to bundle the elements beautifully */}
        <div className="absolute z-10 flex flex-col items-center justify-center text-center max-w-2xl px-8 py-10 rounded-3xl bg-black/40 backdrop-blur-md border border-white/10 shadow-2xl space-y-8 mx-4 transform transition-all duration-1000 hover:shadow-amber-900/10 hover:border-[#A9992D] hover:backdrop-blur-none trasnform scale-58 top-0 left-0">  
          
          {/* Name / Letrero */}
          <div className="w-full max-w-md select-none">
            <p className="VonBom text-[#A9992D] !text-[7.5rem] transition-all duration-700 hover:scale-125"> Cigar  Brevas </p>
          </div>

          {/* Centered Beneficio Panel (Larger fonts) */}
          <div className="w-full border-t border-white/20 pt-6">
            <h3 className="font-name-vitolas uppercase tracking-wider !text-[2rem] md:!text-[2.5rem] text-[#afa697] mb-3 select-none">
              {t("beneficio")}
            </h3>
            <p className="poiret-one-Festy text-white !text-[2.8rem] md:!text-[3.5rem] leading-relaxed select-none font-semibold px-4">
              {t("placer_pausa")}
            </p>
          </div>

        </div>
      </div>
    </>
  );
};

export default Heropage_features;
