import React, { useRef ,  useEffect, useState } from "react";

import { StaticImage } from "gatsby-plugin-image"
import Btn_select from "../components/BtnYesNo";
import Banner from "../components/banner/banner";

import Heropage_features from "../components/hero-Page/heropage";
import Welcome from "../components/welcome/Welcome";
//import Showproduct from "../components/showProduct/ShowProduct";

import CigarVitolar from "../components/cigarVitola/cigarvitola";
import GallerySection from "../components/gallery/GallerySection";
import ShowCigar from "../components/showcigar";

import PrivacyBanner from "../components/privacyBanner/bannerPrivacy";

import LanguageSelector from "../components/selector-idiomas/LanguageSelector"
import Footer from "../components/footer/Footer"
import PwaInstallBanner from "../components/PwaInstallBanner"
import Seo from "../components/seo";
import { useTranslation } from "react-i18next"; 

// import BannerTest from "../components/banner/BannerTest";

// GSAP lazy-loaded below to avoid blocking LCP

const IndexPage = () => {

    const id_up_Fonts = ["aroma" , "maestria"  ,  "consigna" , "tradicion"   ]; 

    const { t } = useTranslation();

    const [logoVisible, setLogoVisible] = useState(() => {
        if (typeof window !== "undefined") {
            const ageOK = localStorage.getItem("edad_Accepted") === "true";
            const visitedOK = localStorage.getItem("visited_cigarBbrevas.com") === "true";
            return !(ageOK && visitedOK);
        }
        return true;
    });
    const [logoFading, setLogoFading] = useState(false);

    useEffect(() => {
        // Guard: only run in browser
        if (typeof window === "undefined") return;

        // Force scroll to top — prevents logo from appearing lowered on back navigation
        window.scrollTo(0, 0);
        // Disable browser scroll restoration so it doesn't override our position
        if (window.history.scrollRestoration) {
            window.history.scrollRestoration = 'manual';
        }

        const age_approve = localStorage.getItem("edad_Accepted") === "true";
        const _visit_cigarBrevas = localStorage.getItem("visited_cigarBbrevas.com") === "true";

        if (typeof document !== "undefined") {
            
            const canScroll = age_approve && _visit_cigarBrevas;
            document.body.style.overflow = canScroll ? "auto" : "hidden";

            if (canScroll) {
                const btnAction = document.getElementById("btn-action");
                if (btnAction) btnAction.style.opacity = "0.5";
            }

                    if(age_approve && _visit_cigarBrevas){


                        id_up_Fonts.forEach(id => {
                            const element = document.getElementById(id);
                            if (element)  {
                                            element.style.fontSize = "1.4em"; // Tamaño inicial pequeño
                            }
                        }
                        );


                        const _quetions = document.getElementById("Question");
                        _quetions.style.display = "none";
                        const _btn_action = document.getElementById("btn-action");
                        _btn_action.style.display = "none";

                        setLogoVisible(false);
                                  }
            
            

        }
    }, []);


    useEffect(() => {
        if (typeof window === "undefined") return;
        console.log(window.innerWidth, "witdh"); 
        console.log(window.innerHeight ,     "heighttttt"); 
    }, []);

    // Load Crisp chat — deferred slightly so it doesn't block LCP
    useEffect(() => {
        if (typeof window === "undefined") return;
        const loadCrisp = () => {
            window.$crisp = [];
            window.CRISP_WEBSITE_ID = "55d98be1-e443-4d1f-9956-9043d5a96863";
            const s = document.createElement("script");
            s.src = "https://client.crisp.chat/l.js";
            s.async = true;
            document.head.appendChild(s);
        };
        // Small delay to let the page render first
        setTimeout(loadCrisp, 1000);
    }, []);


    /*
    const [id_goto , irPorId] = useState[""];

    const irPorId = (id) => {
  const elemento = document.getElementById(id);
  if (elemento) {
    elemento.scrollIntoView({ behavior: 'smooth', block: 'start' });
  }
};
*/

  const contactoRef = useRef(null);

  const scrollToContacto = () => {
    contactoRef.current.scrollIntoView({ behavior: "smooth" });
  };

  const [showLangSelector, setShowLangSelector] = useState(true);
  const langSelectorHidden = useRef(false);

  useEffect(() => {
    if (typeof window === "undefined") return;
    const heroEl = document.getElementById("hero-section");
    if (!heroEl) return;

    const observer = new IntersectionObserver(
      ([entry]) => {
        if (window.innerWidth < 768 && entry.isIntersecting && !langSelectorHidden.current) {
          setShowLangSelector(false);
          langSelectorHidden.current = true;
        }
      },
      { threshold: 0.1 }
    );

    observer.observe(heroEl);

    const onResize = () => {
      if (window.innerWidth >= 768) {
        setShowLangSelector(true);
      }
    };
    window.addEventListener("resize", onResize);

    return () => {
      observer.disconnect();
      window.removeEventListener("resize", onResize);
    };
  }, []);


    // GSAP animation — loaded dynamically after LCP to avoid blocking
    useEffect(() => {
        if (typeof window === "undefined") return;
        let cleanup;
        const initAnim = async () => {
            try {
                const gsapModule = await import('gsap');
                const gsap = gsapModule.default;
                const { useGSAP } = await import('@gsap/react');
                gsap.registerPlugin(useGSAP);

                gsap.from("#consigna", {
                    duration: 2.8,
                    scaleX: 0,
                    opacity: 0,
                    transformOrigin: "center",
                    ease: "power4.out",
                    delay: 2.5,
                });
                gsap.to("#consigna", {
                    duration: 1.2,
                    scaleX: 1,
                    opacity: 1,
                    ease: "expo.out",
                });
            } catch (e) {
                // GSAP failed to load — degrade gracefully
            }
        };
        if (window.requestIdleCallback) {
            requestIdleCallback(initAnim, { timeout: 2000 });
        } else {
            setTimeout(initAnim, 1000);
        }
        return () => { if (cleanup) cleanup(); };
    }, []);

    return (
        <>
        <span className = " w-1/2 "> 

            <PrivacyBanner />
        </span>

        {logoVisible && (
<div id = "logo-section" className={`
  logo-section-position
  right-[4rem] sm:right-[6rem] md:right-[10rem] lg:right-[14rem] xl:right-[18rem] 2xl:right-[22rem] moniT:right-[26rem] dest:right-[30rem] 2k:right-[34rem] 4k:right-[40rem]
  top-0 sm:top-[0.5rem] md:top-[2rem] lg:top-[4rem] xl:top-[6rem] 2xl:top-[8rem] moniT:top-[10rem] dest:top-[12rem] 2k:top-[14rem] 4k:top-[17rem]
  w-[95vw] sm:w-[84vw] md:w-[63vw] lg:w-[53vw] xl:w-[47vw] 2xl:w-[38vw] moniT:w-[33vw] dest:w-[30vw] 2k:w-[26rem] 4k:w-[33rem]
  flex flex-row items-center justify-center
  z-[1000] pointer-events-none
  transition-opacity duration-700
  ${logoFading ? 'opacity-0' : 'opacity-100'}
`}>
                        <StaticImage
                            src="../assets/images/page2/name-cigar-brevas.webp"
                            alt="Cigarros Brevas logo"
                            className=   "object-contain h-auto w-full"
                            placeholder="dominantColor"
                            loading="eager"
                            fetchPriority="high"
                        />
                        {/* <h1 className="VonBom text-[#A9992D] transform translate-x-[4rem] relative  mb-9 text-5xl md:text-8xl drop-shadow-[0_4px_12px_rgba(28,51,17,0.15)] tracking-tighter">
            Cigars&nbsp;&nbsp;Brevas
          </h1> */}
</div>
                        )}

                        {showLangSelector && (
                        <div className="bg-black/20  absolute wrap z-999 h-1/2 left-[5rem]  mr-15 pr-3 flex flex-col  items-center justify-center languageSelector">
                            <span className="z-40 relative right-0 block-[content]  w-[content]">
                                <LanguageSelector />
                               
                            </span>
                        </div>
                        )}


            <main className= "bg-main border border-[#007F0D] relative left-0 top-[-4] min-h-screen overflow-visible" >
                <div className="left"></div>
                <div className="right"></div>

                {/* Layer 1: Background Images */}
                <section className="min-w-full  min-h-screen flex items-center justify-center absolute left-0 top-0 z-0">
                    <section className="grid grid-cols-4 w-full h-dvh grid-rows-3 gap-[3vw] gap-y-0.5 p-0">
                        <div className="bg-black/5"></div>
                        <div className="bg-black/5"></div>
                        <StaticImage
                            src="../assets/images/page1/perilla-cigar-Brevas.webp"
                            alt="Imagen perillas bitola N°5"
                            className="page-reveal aspect-square w-full h-full object-cover pointer-events-none user-select-none"
                            layout="constrained"
                            quality={95}
                            placeholder="dominantColor"
                            onContextMenu={(e) => e.preventDefault()}
                        />

                                     <div className="flex justify-end-safe items-stretch">
                        <StaticImage
                            src="../assets/images/page1/fachada-cigar-Brevas.webp"
                            alt="Imagen fachada de Cigar Brevas"
                            className="page-reveal right-0 aspect-square w-1/2 h-1/2 object-cover pointer-events-none user-select-none"
                            layout="constrained"
                            quality={95}
                            placeholder="dominantColor"
                            onContextMenu={(e) => e.preventDefault()}
                        />
                        </div>

                        <StaticImage
                            src="../assets/images/page1/-cigar-name-logo.webp"
                            alt="Imagen abuela torcedora trabajadora"
                            className= "page-reveal border border-[#A8982D] border-3  aspect-video w-full h-full object-cover pointer-events-none user-select-none"
                            layout="constrained"
                            quality={95}
                            placeholder="dominantColor"
                            onContextMenu={(e) => e.preventDefault()}
                        />
                        <div className="bg-black/5"></div>
                        <div className="flex justify-end-safe items-stretch">
                            <StaticImage
                                src="../assets/images/page1/solo-cortadora-Cigar-Brevas.webp"
                                alt="Imagen Cortadora de Cigarro Brevas"
                                className=" page-reveal  w-3/4 h-3/4 object-cover pointer-events-none right-0 user-select-none"
                                layout="constrained"
                                
                                quality={95}
                                placeholder="dominantColor"
                                onContextMenu={(e) => e.preventDefault()}
                            />
                        </div>

                        <div className="flex justify-end bottom-0 items-stretch">
                            <StaticImage
                                src="../assets/images/page1/rollero-cortadora-cigar-brevas.webp"
                                alt="Imagen Maquina de Rollero y cortadora"
                                className="page-reveal w-3/4 h-3/4 object-cover pointer-events-none user-select-none"
                                layout="constrained"
                                
                                quality={95}
                                placeholder="dominantColor"
                                onContextMenu={(e) => e.preventDefault()}
                            />
                        </div>
                        <div className="bg-black/5"></div>
                        <div className="bg-black/5"></div>
                        <div className="flex justify-end-safe items-stretch">
                            <StaticImage
                                src="../assets/images/page1/cigar-Brevas-tabaco-Flor.webp"
                                alt="Imagen tabaco flor"
                                className="page-reveal w-33 h-full object-cover pointer-events-none user-select-none"
                                layout="constrained"
                                quality={95}
                                placeholder="dominantColor"
                                onContextMenu={(e) => e.preventDefault()}
                            />
                        </div>
                    </section>
                </section>

                {/* Layer 2: Decorative Grid Text */}
                <section className = "w-full h-dvh grid grid-cols-4 grid-rows-3 absolute left-0 top-0 z-10 pointer-events-none">
                    <div className = "chevron transform rotation-190 w-full flex items-center justify-center">
                        
{/*              line vertical                   */}
<div className="vertical-line">
  <div className="circle"></div>
</div>
                        <div>
                            <span className = "  text-fluid-mini text-center w-full vertical-text text-[funnel]">
                                {t("decorativo_tiempo")}
                            </span>
                            <span className = "mr-22 mt-12 left-[15rem]  relative text-[0.3rem] text-white text-fluid-mini text-center w-full vertical-text text-[funnel] ">
                                {t("decorativo_jubilo")}
                            </span>
                        </div>
                    </div>

                    <div className="col-span-2 flex items-center justify-center">
                        <svg viewBox="0 0 400 100" className="w-full h-24 mx-auto">
                            <text x="0" y="60" className="text-[0.9em] letter-spacing-[3px] stroke-[#A8982D] fill-none" strokeWidth="1">
                                 hand MADE
                                <animate attributeName = "stroke-dasharray" from="0,200" to="200,0" dur="2s" fill="freeze" />
                            </text>
                        </svg>
                    </div>

                    <div className="chevron w-full relative top-8 text-wrap flex items-center justify-center">
                        <span id= "tradicion" className="top-7 relative   text-[funnel] text-center w-full text-white">{t("decorativo_tradicion")}</span>
                    </div>

                            {/*              line vertical                   */}
<div className="vertical-line h-1/2 bottom-5 relative w-1">
  <div className="circle"></div>
</div>


                    <div className="text-center w-full vertical-text text-white flex items-center justify-center">{t("decorativo_pasion")}</div>

                    <div className="chevron w-full flex items-center justify-center">
                        <span id = "aroma" className="  left-[-9em] vertical-text relative bottom-0.1 text-left text-[#A8982D] w-full">{t("decorativo_aroma")}</span>
                    </div>

                    <div className="chevron w-full flex items-center justify-center">
                        <span className="text-fluid-mini text-center w-full text-gray-100">{t("decorativo_arte")}</span>
                    </div>

                    <div className="chevron w-full flex items-center justify-center">
                        <span className="text-[2px] text-fluid-mini text-center w-full">{t("decorativo_serenidad")}</span>
                    </div>
 <div id="maestria" className="chevron w-full flex items-center justify-center">
                        <span className="text-[2px] text-fluid-mini text-center w-full text-white">{t("decorativo_maestria")}</span>
                    </div>

                    <div className=" w-full mb-[3rem] flex items-center justify-center text-wrap w-[33wv] bottom-[50wv] relative  ">
                        <span  id= "consigna"  className="xsm:text-[1.2rem]  text-[1.2px] bg-[#C42B25]/77  text-white  text-center w-full">
                            {t("decorativo_consigna")}
                        </span>
                    </div>

                    <div className="chevron w-full block-0 bottom-0 flex items-center justify-center">
                        <span className="text-white  text-fluid-mini text-center w-full">{t("decorativo_calidad")}</span>
                    </div>

                    <div className="chevron w-full flex items-center justify-center">
                        <span className="text-center w-full">{t("decorativo_satisfaccion")}</span>
                    </div>

                    <div className="flecha-completa w-full col-span-2 text-center flex items-center justify-center text-white">{t("decorativo_dedicacion")}</div>
                </section>



                {/* Layer 3: Foreground Content */}
               <section
  id="Question"
  className="
    z-20 text-bungeespice text-fluid
    w-full h-dvh
    flex flex-col
    absolute left-0 top-0
    pointer-events-none
  "
>
  {/* Línea 1: “tienes” */}
  <div
    className="
      flex justify-center items-center
      w-full px-4 sm:px-8 md:px-16
    "
  >
    <span
      className="
        mt-16 w-full
        text-center
        bungee-Tint-regular
        pointer-events-auto
        drop-shadow-sm drop-shadow-black/40
        md:text-left md:ml-24
        moniT:ml-40
        2k:ml-64
        4k:ml-80
      "
    >
      {t("tienes")}
    </span>
  </div>

  {/* Línea 2: pregunta central */}
  <div
    className="
      mt-4
      w-full
      text-center
      bungee-Tint-regular
      text-[clamp(1.7rem,2vw+0.8rem,2.9rem)]
      pointer-events-auto
      md:mt-8
      md:text-left md:pl-24
      moniT:pl-40
      2k:pl-64
      4k:pl-80
    "
  >
    {t("edad_label")}
  </div>

  {/* Reloj */}
  <div className="mt-6 flex justify-center items-center pointer-events-auto">
    <svg viewBox="0 0 400 150" className="w-52 h-20">
      <text
        x="150"
        y="80"
        fontSize="20"
        fontFamily="Fira Code"
        fill="white"
      >
        {t("decorativo_tiempo")}
      </text>
      <ellipse
        cx="200"
        cy="75"
        rx="150"
        ry="50"
        stroke="red"
        fill="none"
        strokeWidth="3"
        className="anim-ellipse"
      />
    </svg>
  </div>

  {/* “edad suficiente” */}
  <div
    className="
      relative
      mt-8
      w-full
      flex items-center justify-center
      pointer-events-auto
    "
  >
    <div
      className="
      sm:mt-12
        suficiente 
        bungee-Tint-regular
        drop-shadow-2xl drop-shadow-green-700/50
        text-center
        md:text-left
        md:pl-24
        moniT:pl-40
        2k:pl-64
        4k:pl-80
      "
    >
      {t("edad_suficiente")}
    </div>
  </div>

  {/* “para fumar” + icono */}
  <div
    className="
      relative parafumar
      mt-6
      w-full
      text-center
      bungee-Tint-regular
      pointer-events-auto
      md:text-left
      md:pl-24
      moniT:pl-40
      2k:pl-64
      4k:pl-80
    "
  >
    {t("para_fumar")}
    <div className="inline-flex justify-end items-center ml-4 align-middle">
      <StaticImage
        src="../assets/images/page1/icon-alarm.webp"
        alt="Imagen Icon Alarm"
        className="w-12 h-12 md:w-16 md:h-16 object-contain pointer-events-none"
        layout="constrained"
        quality={95}
        placeholder="dominantColor"
        onContextMenu={(e) => e.preventDefault()}
      />
    </div>
  </div>
</section>

                <div className = "btn-lenguaje-selection w-full h-auto absolute bottom-0 z-999">
                            <Btn_select className="z-10" onAgeVerified={() => {
                                setLogoFading(true);
                                setTimeout(() => setLogoVisible(false), 700);
                            }} />
                        </div>

                <section className = "w-1/4 h-14 bottom-0 absolute m-[20px] bottom-[-30px] flex flex-row z-30 bg-white/50 backdrop-blur-sm ">
                    <span className = "text-black m-auto p-1.5 firstPage-word-font-bold text-center box-content">
                        {t("prohibida_venta")}
                    </span>
                </section> 

            </main>



<div className="mt-9 bg-transparent max-w-full" >

    <Banner />
</div>


            <div id="hero-section" className = "min-h-screen  w-[100%]">
                <Heropage_features />
            </div>

            <div className="mt-15 w-[78vw] moniT:w-full  relative z-1 m-auto bg-white flex flex-col items-center justify-center">
                <Welcome />
            </div>

            <div id="contactoRef_vitolar" className="relative left-0 top-0 m-0 p-0 min-h-screen">
                <CigarVitolar />
            </div>

            <div id="compras" className="min-h-screen w-full relative flex flex-col justify-center left-0 top-0 mt-0 transform scale-[0.80]   2k:scale-100 4k:scale-125">
                <ShowCigar />
            </div>
<footer> 
            <div className="w-full">
                <GallerySection />
            </div>
</footer>






            <Footer />
            <PwaInstallBanner />
        </>
    );
};

export const Head = () => (
    <Seo
      title="Puros Brevas"
      description="Cigarros artesanales colombianos de alta calidad. Tradición desde 1974. Churchill, Torpedo, Número 5, Puritos, Panetela, Robusto y Aromados."
      pathname="/"
      lang="es"
    />
);

export default IndexPage;