import React, { useState, useEffect } from "react";
import { useTranslation } from "react-i18next";

/**
 * PwaInstallBanner
 * ────────────────────────────────
 * Floating banner fixed at the bottom of the screen that prompts the user
 * to install the PWA. Visible across all sections of the webpage.
 *
 * - Detects `beforeinstallprompt` event
 * - Hides after install or in standalone mode
 * - User can dismiss it permanently (localStorage)
 */
const PwaInstallBanner = () => {
  const { t } = useTranslation();
  const [deferredPrompt, setDeferredPrompt] = useState(null);
  const [isInstalled, setIsInstalled] = useState(false);
  const [isStandalone, setIsStandalone] = useState(false);
  const [dismissed, setDismissed] = useState(false);

  useEffect(() => {
    // Check if already running as standalone PWA
    if (
      typeof window !== "undefined" &&
      (window.matchMedia("(display-mode: standalone)").matches ||
        window.navigator.standalone)
    ) {
      setIsStandalone(true);
    }

    // Check if user dismissed the banner before
    if (typeof window !== "undefined") {
      const dismissedBefore = localStorage.getItem("pwa_banner_dismissed");
      if (dismissedBefore === "true") {
        setDismissed(true);
      }
    }

    const handler = (e) => {
      e.preventDefault();
      setDeferredPrompt(e);
    };

    window.addEventListener("beforeinstallprompt", handler);

    window.addEventListener("appinstalled", () => {
      setIsInstalled(true);
      setDeferredPrompt(null);
    });

    return () => {
      window.removeEventListener("beforeinstallprompt", handler);
    };
  }, []);

  const handleInstallClick = async () => {
    if (!deferredPrompt) return;
    deferredPrompt.prompt();
    const result = await deferredPrompt.userChoice;
    if (result.outcome === "accepted") {
      setIsInstalled(true);
      // Also mark as dismissed for good measure
      localStorage.setItem("pwa_banner_dismissed", "true");
    }
    setDeferredPrompt(null);
  };

  const handleDismiss = () => {
    setDismissed(true);
    localStorage.setItem("pwa_banner_dismissed", "true");
  };

  // Don't show if installed, standalone, dismissed, or no prompt available
  const show = !isInstalled && !isStandalone && !dismissed;

  if (!show) return null;

  return (
    <div
      className="fixed bottom-0 left-0 right-0 z-[9999] animate-slide-up"
      style={{
        animation: "slideUp 0.5s cubic-bezier(0.34, 1.56, 0.64, 1) forwards",
      }}
    >
      <style>{`
        @keyframes slideUp {
          from { transform: translateY(100%); opacity: 0; }
          to { transform: translateY(0); opacity: 1; }
        }
        @keyframes pulse-glow {
          0%, 100% { box-shadow: 0 0 12px rgba(120, 54, 137, 0.3); }
          50% { box-shadow: 0 0 24px rgba(120, 54, 137, 0.6); }
        }
        .pwa-banner-pulse {
          animation: pulse-glow 2s ease-in-out infinite;
        }
      `}</style>

      <div className="relative mx-auto max-w-7xl px-4 pb-4 sm:px-6">
        <div
          className={`relative flex flex-col sm:flex-row items-center justify-between gap-3 rounded-2xl p-4 sm:p-5 shadow-2xl border border-white/20 backdrop-blur-md transition-all duration-300 ${
            deferredPrompt
              ? "bg-[#783689]/95 pwa-banner-pulse"
              : "bg-[#9b7f49]/95"
          }`}
        >
          {/* Close button */}
          <button
            onClick={handleDismiss}
            className="absolute -top-2 -right-2 w-7 h-7 bg-white/20 hover:bg-white/40 rounded-full flex items-center justify-center text-white text-sm font-bold transition-all hover:scale-110 cursor-pointer"
            aria-label="Cerrar"
            title="Cerrar"
          >
            ✕
          </button>

          {/* Left: Icon + Text */}
          <div className="flex items-center gap-3 sm:gap-4 flex-1 min-w-0">
            {/* Download icon */}
            <div className="flex-shrink-0 w-10 h-10 sm:w-12 sm:h-12 bg-white/20 rounded-full flex items-center justify-center">
              <svg
                xmlns="http://www.w3.org/2000/svg"
                viewBox="0 0 24 24"
                fill="white"
                className="w-5 h-5 sm:w-6 sm:h-6"
              >
                <path d="M12 16.5a.75.75 0 0 1-.75-.75V5.81l-2.22 2.22a.75.75 0 0 1-1.06-1.06l3.5-3.5a.75.75 0 0 1 1.06 0l3.5 3.5a.75.75 0 0 1-1.06 1.06L12.75 5.81v9.94c0 .414-.336.75-.75.75Z" />
                <path d="M4.5 15.75a.75.75 0 0 1 .75.75v1.5a1.5 1.5 0 0 0 1.5 1.5h10.5a1.5 1.5 0 0 0 1.5-1.5v-1.5a.75.75 0 0 1 1.5 0v1.5a3 3 0 0 1-3 3H6.75a3 3 0 0 1-3-3v-1.5a.75.75 0 0 1 .75-.75Z" />
              </svg>
            </div>

            {/* Text */}
            <div className="text-white min-w-0">
              <p className="text-[0.95rem] sm:text-[1.05rem] font-extrabold leading-tight">
                {t("gracias_visita") || "Instala nuestra App"}
              </p>
              <p className="text-[0.7rem] sm:text-[0.8rem] opacity-80 leading-tight mt-0.5 hidden sm:block">
                Accede rápido desde tu pantalla de inicio
              </p>
            </div>
          </div>

          {/* Right: Install + Maybe Later buttons */}
          <div className="flex items-center gap-2 flex-shrink-0">
            <button
              onClick={handleDismiss}
              className="px-3 py-2 rounded-lg text-white/70 hover:text-white text-[0.75rem] sm:text-[0.85rem] font-bold transition-all hover:bg-white/10 cursor-pointer whitespace-nowrap"
            >
              Ahora no
            </button>
            {deferredPrompt ? (
              <button
                onClick={handleInstallClick}
                className="px-5 py-2.5 rounded-xl bg-white text-[#783689] hover:bg-[#f0e6f5] text-[0.85rem] sm:text-[0.95rem] font-extrabold transition-all hover:scale-105 active:scale-95 shadow-lg cursor-pointer whitespace-nowrap"
              >
                {t("aceptar") || "Instalar"}
              </button>
            ) : (
              <button
                disabled
                className="px-5 py-2.5 rounded-xl bg-white/40 text-white/60 text-[0.85rem] sm:text-[0.95rem] font-extrabold cursor-not-allowed whitespace-nowrap opacity-60"
              >
                Cargando...
              </button>
            )}
          </div>
        </div>
      </div>
    </div>
  );
};

export default PwaInstallBanner;
