import React, { useState, useEffect, useRef } from 'react';
import { CigarVitolas_Price } from '../page-data/page-data';
import gsap from 'gsap';
import { useTranslation } from 'react-i18next';
import { asset } from '../utils/assetPath';

const ShowCigar = () => {
  const { t } = useTranslation();
  const [loading, setLoading] = useState(true);
  const [showVoucherOptions, setShowVoucherOptions] = useState(false);
  const [voucher, setVoucher] = useState([]);
  const [exchangeRate, setRate] = useState(null);
  const [isCompraVisible, setIsCompraVisible] = useState(true);
  const [selectedProductIndex, setSelectedProductIndex] = useState(0);

  const data_cigar = CigarVitolas_Price.Show_Cigar;
  const selected_card = data_cigar[selectedProductIndex];
  const first_image = selected_card?.src_image1;
  const name_cigar = selected_card?.item_product_cuantiti;
  const cantidad_unidades = selected_card?.cantidad_unidades;
  const item_count = selected_card?.num_item;
  const precio = selected_card?.precio;

  const parsePrice = (priceStr) => {
    if (!priceStr) return 0;
    return parseInt(priceStr.replace(/\./g, ""), 10);
  };

  const totalCOP = voucher.reduce((sum, item) => sum + parsePrice(item.precio), 0);
  const totalUSD = exchangeRate ? (totalCOP / exchangeRate).toFixed(2) : 0;

  useEffect(() => {
    setLoading(false);
  }, []);

  useEffect(() => {
    const getRate = async () => {
      try {
        const response = await fetch("https://api.exchangerate-api.com/v4/latest/USD");
        const data = await response.json();
        setRate(data.rates.COP);
      } catch (error) {
        console.error("Error consultando la tasa:", error);
      }
    };
    getRate();
  }, []);

  useEffect(() => {
    if (typeof window === "undefined") return;
    const el = document.querySelector('[data-showcigar="true"]');
    if (!el) return;
    const observer = new IntersectionObserver(
      ([entry]) => setIsCompraVisible(entry.isIntersecting),
      { threshold: 0.2 }
    );
    observer.observe(el);
    return () => observer.disconnect();
  }, []);

  const addProduct = (e) => {
    const productToAdd = {
      name: name_cigar,
      presentation: cantidad_unidades,
      precio: precio,
    };
    setVoucher([...voucher, productToAdd]);

    // Animate + scroll only on mobile
    const btn = e?.currentTarget;
    if (btn && typeof window !== 'undefined' && window.innerWidth < 768) {
      gsap.fromTo(
        btn,
        { scale: 1 },
        {
          scale: 1.3,
          duration: 0.3,
          ease: 'power2.inOut',
          yoyo: true,
          repeat: 1,
          onComplete: () => {
            // Scroll to voucher after animation
            if (voucherRef.current) {
              voucherRef.current.scrollIntoView({ behavior: 'smooth', block: 'start' });
            }
          },
        }
      );
    }
  };

  const removeProduct = (index) => {
    setVoucher(voucher.filter((_, i) => i !== index));
  };

  const sendWhatsApp = () => {
    if (voucher.length === 0) return;
    let message = t("pedido_msg") + "\n\n";
    voucher.forEach((item, index) => {
      message += `${index + 1}. ${item.name} - ${item.presentation} ($${item.precio} COP)\n`;
    });
    message += `\n${t("total_cop")}: $${totalCOP.toLocaleString("es-CO")}\n`;
    message += `${t("total_usd")}: $${totalUSD}\n`;
    const encodedMessage = encodeURIComponent(message);
    window.open(`https://wa.me/573174044408?text=${encodedMessage}`, "_blank");
  };

  const sendTelegram = () => {
    if (voucher.length === 0) return;
    let message = t("pedido_msg") + "\n\n";
    voucher.forEach((item, index) => {
      message += `${index + 1}. ${item.name} - ${item.presentation} ($${item.precio} COP)\n`;
    });
    message += `\n${t("total_cop")}: $${totalCOP.toLocaleString("es-CO")}\n`;
    message += `${t("total_usd")}: $${totalUSD}\n`;
    const encodedMessage = encodeURIComponent(message);
    window.open(`https://t.me/cigargamospurosbrevas?text=${encodedMessage}`, "_blank");
  };

  // Get unique cigar types (group by id)
  const uniqueCigars = [];
  const seenIds = new Set();
  data_cigar.forEach(product => {
    if (!seenIds.has(product.id)) {
      uniqueCigars.push(product);
      seenIds.add(product.id);
    }
  });

  // Reorder unique cigars to alternate columns
  const reorderedCigars = [];
  const mid = Math.ceil(uniqueCigars.length / 2);
  for (let i = 0; i < mid; i++) {
    reorderedCigars.push(uniqueCigars[i]);
    if (mid + i < uniqueCigars.length) {
      reorderedCigars.push(uniqueCigars[mid + i]);
    }
  }

  const badgesRef = useRef(null);
  const priceRef = useRef(null);
  const qtyRef = useRef(null);
  const voucherRef = useRef(null);

  // Yoyo animation on price and quantity when product changes
  const prevProductIndex = useRef(selectedProductIndex);
  useEffect(() => {
    if (typeof window === 'undefined') return;
    if (prevProductIndex.current === selectedProductIndex) return;
    prevProductIndex.current = selectedProductIndex;

    const elements = [priceRef.current, qtyRef.current].filter(Boolean);
    if (elements.length === 0) return;

    gsap.fromTo(
      elements,
      { scale: 1 },
      {
        scale: 1.15,
        duration: 0.3,
        ease: 'power2.inOut',
        yoyo: true,
        repeat: 5, // 3 yoyo cycles
        stagger: 0.15,
      }
    );
  }, [selectedProductIndex]);

  // Yoyo animation on quantity badges when section enters viewport
  useEffect(() => {
    if (typeof window === 'undefined' || !badgesRef.current) return;
    const badges = badgesRef.current.querySelectorAll('.qty-badge');
    if (badges.length === 0) return;

    const ctx = gsap.context(() => {
      gsap.fromTo(
        badges,
        { scale: 1 },
        {
          scale: 1.3,
          duration: 0.3,
          ease: 'power2.inOut',
          yoyo: true,
          repeat: 5,
          delay: 1.2,
          stagger: 0.1,
        }
      );
    }, badgesRef.current);

    return () => ctx.revert();
  }, []);

  if (loading) {
    return <div className="text-center py-8">{t("cargando")}</div>;
  }

  // Key for triggering animations on product change
  const animKey = `anim-${selectedProductIndex}`;

  return (
    <>
      <style>{`
        @keyframes fadeInScale {
          from { opacity: 0; transform: scale(0.95); }
          to { opacity: 1; transform: scale(1); }
        }
        .animate-fade-in-scale {
          animation: fadeInScale 0.4s ease-out forwards;
        }
        @keyframes fadeInScale120 {
          from { opacity: 0; transform: scale(0.95); }
          to { opacity: 1; transform: scale(1.2); }
        }
        .animate-fade-in-scale-120 {
          animation: fadeInScale120 0.4s ease-out forwards;
        }
        @keyframes fadeInScale150 {
          from { opacity: 0; transform: scale(1.425); }
          to { opacity: 1; transform: scale(1.5); }
        }
        .animate-fade-in-scale-150 {
          animation: fadeInScale150 0.4s ease-out forwards;
        }
        .voucher-scroll::-webkit-scrollbar {
          width: 6px;
          display: block;
        }
        .voucher-scroll::-webkit-scrollbar-track {
          background: rgba(255,255,255,0.1);
          border-radius: 3px;
        }
        .voucher-scroll::-webkit-scrollbar-thumb {
          background: #FFA201;
          border-radius: 3px;
        }

        @media (max-width: 360px) {
          [data-showcigar="true"] {
            zoom: 0.8;
          }
        }
      `}</style>
    <div className="w-full min-h-screen bg-white" data-showcigar="true">
      <div className="max-w-7xl mx-auto grid grid-cols-1 md:grid-cols-3 gap-0 relative">

        {/* Signus-plus btn: desktop between voucher and selector, mobile top of selector */}
        <divi id = "addProduct-btn"
          onClick={addProduct}
          className="hidden md:block absolute left-[calc(33.33%-4rem)] top-[10%] w-[8rem] h-[8rem] cursor-pointer hover:scale-110 transition-transform z-[999]"
        >
          <img
            src={asset('/cigar-vitola/-pluss-count.png')}
            alt="Add product"
            className="object-contain pointer-events-none select-none w-full h-full"
          />
        </divi>

        {/* COLUMN 1 - VOUCHER */}
        <div ref={voucherRef} className="bg-purple-900 flex flex-col shadow-2xl border border-yellow-500/30 h-screen relative overflow-y-auto voucher-scroll">

          <div
            onClick={() => setShowVoucherOptions(!showVoucherOptions)}
            className="w-full py-3 px-4 text-center border-b border-white/10 cursor-pointer hover:bg-purple-800 transition-colors relative"
          >
            <p className="text-[2.875rem] md:text-xl font-extrabold text-white uppercase tracking-wider">
              {t("voucher")}
            </p>

            {showVoucherOptions && (
              <div className="absolute top-full left-1/2 transform -translate-x-1/2 bg-white text-black rounded-lg shadow-lg p-3 w-40 z-50 mt-2">
                <button
                  onClick={(e) => { e.stopPropagation(); sendWhatsApp(); setShowVoucherOptions(false); }}
                  className="block w-full text-left px-3 py-2 hover:bg-green-400 hover:text-white rounded mb-2 text-sm font-bold transition-colors"
                >
                  💬 WhatsApp
                </button>
                <button
                  onClick={(e) => { e.stopPropagation(); sendTelegram(); setShowVoucherOptions(false); }}
                  className="block w-full text-left px-3 py-2 hover:bg-blue-400 hover:text-white rounded text-sm font-bold transition-colors"
                >
                  📱 Telegram
                </button>
              </div>
            )}
          </div>

          {voucher.length > 0 ? (
            <div className="text-white text-center flex flex-col items-center justify-start w-full flex-1 p-3">
              <div className="w-full flex-1 overflow-y-auto space-y-1 pr-1">
                {voucher.map((item, index) => (
                  <div
                    key={index}
                    className="bg-yellow-400 text-black p-1 rounded-lg border border-white/10 flex flex-col items-center justify-center hover:bg-yellow-500 transition"
                  >
                    <div className="flex items-center justify-between w-full">
                      <div className="flex flex-col items-start min-w-0 mr-2">
                        <p className="font-bold text-[2.24rem] md:text-[0.98rem] leading-none truncate w-full">{item.name}</p>
                        {item.presentation && (
                          <p className="text-[1.6rem] md:text-[0.7rem] opacity-75 leading-tight mt-1">{item.presentation}</p>
                        )}
                      </div>
                      <p className="text-[2.16rem] md:text-[0.94rem] opacity-90 font-medium leading-none whitespace-nowrap">${item.precio}</p>
                    </div>
                    <button
                      onClick={() => removeProduct(index)}
                      className="bg-red-500 hover:bg-red-600 text-white rounded px-3 py-1.5 text-[2.16rem] md:text-[0.94rem] font-bold transition mt-1"
                    >
                      ✕ {t("quitar")}
                    </button>
                  </div>
                ))}
              </div>

              <div className="border-t border-white/30 pt-2 mt-2 w-full space-y-1">
                <div key={`total-cop-${totalCOP}`} className="text-black p-2 rounded text-center font-extrabold animate-fade-in-scale-120 text-[2.24rem] md:text-[0.96rem]" style={{ backgroundColor: '#FACC15' }}>
                  ${totalCOP.toLocaleString("es-CO")} COP
                </div>
                <div key={`total-usd-${totalUSD}`} className="text-black p-1.5 rounded text-center font-bold animate-fade-in-scale-120 text-[1.84rem] md:text-[0.8rem]" style={{ backgroundColor: '#FDE047', animationDelay: '0.15s' }}>
                  ${totalUSD} USD
                </div>
              </div>
            </div>
          ) : (
            <div className="flex-1 flex items-center justify-center text-white text-[2rem] md:text-sm font-normal text-center px-3 italic opacity-75">
              <p>{t("agrega_productos")}</p>
            </div>
          )}

          <div className="flex flex-row justify-center gap-3 pb-3 px-2">
            <div
              onClick={sendWhatsApp}
              className="cursor-pointer group flex flex-col items-center transition-all hover:scale-110"
            >
              <div className="bg-white p-2 rounded-full shadow-lg">
                <img
                  src={asset('/footer/-logo-msn-whatup.webp')}
                  alt="WhatsApp"
                  className="w-[3.94rem] h-[3.94rem]"
                />
              </div>
              <span className="text-white text-[1.96rem] md:text-[0.85rem] font-bold mt-1 uppercase tracking-wider">{t("solicitar")}</span>
            </div>

            <div
              onClick={sendTelegram}
              className="cursor-pointer group flex flex-col items-center transition-all hover:scale-110"
            >
              <div className="bg-white p-2 rounded-full shadow-lg">
                <img
                  src={asset('/footer/-logo-msn-telegram.webp')}
                  alt="Telegram"
                  className="w-[3.94rem] h-[3.94rem]"
                />
              </div>
              <span className="text-white text-[1.96rem] md:text-[0.85rem] font-bold mt-1 uppercase tracking-wider">{t("solicitar")}</span>
            </div>
          </div>


        </div>

        {/* COLUMN 2 - VITOLA SELECTOR (adjacent to voucher) */}
        <div className="flex flex-col relative">
          <div className="p-4 flex-1 overflow-y-auto" style={{ backgroundColor: '#4A6741' }}>
            <p className="font-name-title text-white text-center mb-4" style={{ fontSize: '2.1rem' }}>{t("selecciona_vitola")}</p>

            {/* Casilla src_image2 con fondo amber-700 */}
            <div className="bg-[#C2AB00] rounded-lg p-3 mb-4">
              <div className="flex items-center justify-center">
                <img
                  key={`img2-${selectedProductIndex}`}
                  src={selected_card?.src_image2}
                  alt={name_cigar}
                  className="w-full max-w-[200px] h-auto object-contain pointer-events-none select-none animate-fade-in-scale"
                />
              </div>
            </div>

            {/* Price moved here: between amber-700 box and vitola names */}
            <div ref={priceRef} key={`price-${selectedProductIndex}`} className="mb-4 text-white p-4 rounded w-full text-center font-bold animate-fade-in-scale" style={{ backgroundColor: '#FFA201', fontSize: '1.82rem', animationDelay: '2s' }}>
              <span>{t("precio_label")} ${precio} COP</span>
            </div>

            <div ref={badgesRef} className="grid grid-cols-2 md:grid-cols-3 gap-6">
              {reorderedCigars.map((product) => {
                const presentations = data_cigar.filter(p => p.id === product.id);
                const hasMultiple = presentations.length > 1;

                return (
                  <div key={product.id} className="flex flex-col gap-2 relative">
                    {/* Vitola Button */}
                    <button
                      onClick={() => {
                        const index = data_cigar.findIndex(p => p.id === product.id);
                        if (index !== -1) setSelectedProductIndex(index);
                      }}
                      className={`p-2 rounded text-center transition-all text-[1.6rem] md:text-[1.125rem] font-bold font-name-vitolas ${
                        selected_card?.id === product.id
                          ? 'bg-yellow-400 text-black'
                          : 'bg-white hover:bg-gray-200'
                      }`}
                    >
                      <div className="text-[1.5rem] md:text-[1.075rem] font-extrabold">
                        {(() => {
                          const cleaned = product.item_product_cuantiti.replace(/\s+/g, ' ').trim();
                          const parts = cleaned.split('Cigar Brevas ');
                          if (parts.length > 1) {
                            const vitolaName = parts[1].trim();
                            const longVitolas = ['PANETELA', 'NUMERO 5', 'CHURCHILL', 'AROMADO'];
                            const isLong = longVitolas.includes(vitolaName);
                            return (
                              <>
                                <span className="text-[1.35rem] md:text-[0.975rem] opacity-70">Cigar Brevas</span>
                                <br />
                                <span className={isLong ? 'text-[1.1rem] md:text-[0.8rem] whitespace-nowrap' : ''}>{vitolaName}</span>
                              </>
                            );
                          }
                          return cleaned;
                        })()}
                      </div>
                      {hasMultiple && (
                        <div className="flex gap-1 justify-center mt-1">
                          {presentations.map((pres, idx) => {
                            const qty = pres.cantidad_unidades.match(/(\d+)\s*UNIDADES/)?.[1];
                            return (
                              <span
                                key={`exp-${idx}`}
                                className={`qty-badge text-[1.325rem] font-bold mx-1 px-1 py-0.5 rounded transition-all cursor-pointer ${
                                  selectedProductIndex === data_cigar.indexOf(pres)
                                    ? 'text-white font-extrabold'
                                    : 'text-white/80 hover:text-[#ff00ff]'
                                }`}
                                onClick={(e) => {
                                  e.stopPropagation();
                                  setSelectedProductIndex(data_cigar.indexOf(pres));
                                }}
                                style={{ backgroundColor: selectedProductIndex === data_cigar.indexOf(pres) ? '#ff00ff' : '#9B7F49' }}
                              >
                                {qty}
                              </span>
                            );
                          })}
                        </div>
                      )}
                    </button>
                  </div>
                );
              })}
            </div>
          </div>
        </div>

        {/* COLUMN 3 - CENTER / MAIN CONTENT */}
        <div className="flex flex-col">
          {/* Tan Background with Brown Frame */}
          <div className="bg-[#C2AB00] p-8 flex-1 flex items-center justify-center relative">
            <div className="w-full max-w-[clamp(260px,52vw,520px)] aspect-square bg-[#9B7F49] rounded-xl shadow-lg overflow-hidden flex items-center justify-center border border-[#783689]/20 relative">
              <img
                key={`img1-${selectedProductIndex}`}
                src={asset(first_image)}
                alt="Cigar"
                className={`object-contain pointer-events-none select-none w-full h-full p-[5px] transition-transform duration-500 ease-out ${selected_card?.id === 4 ? 'animate-fade-in-scale' : 'animate-fade-in-scale-150'}`}
              />

              {/* Mobile add button: on top of the image */}
              <divi
                onClick={addProduct}
                className="md:hidden absolute bottom-2 right-2 w-[7rem] h-[7rem] cursor-pointer hover:scale-110 transition-transform z-[999]"
              >
                <img
                  src={asset('/cigar-vitola/-pluss-count.png')}
                  alt="Add product"
                  className="object-contain pointer-events-none select-none w-full h-full"
                />
              </divi>
            </div>

            {/* Number Badge */}
            <div className="absolute top-6 left-6 bg-yellow-400 text-black rounded-full w-16 h-16 flex items-center justify-center font-bold text-2xl">
              {item_count}
            </div>
          </div>

          {/* Yellow Label Section */}
          <div className="bg-yellow-400 text-black p-6 text-center">
            <h3 className="font-name-title text-2xl">{name_cigar}</h3>
          </div>

          {/* Text Content */}
          <div className="bg-white p-8 text-gray-900">
            <p ref={qtyRef} key={`qty-${selectedProductIndex}`} className="mt-4 mb-8 text-white p-4 rounded w-full text-center font-bold animate-fade-in-scale" style={{ backgroundColor: '#4A6741', fontSize: '1.4rem', animationDelay: '2s' }}>{cantidad_unidades}</p>
            <p className="text-[1.68rem] leading-relaxed">
              {t("descripcion_producto")}
            </p>
          </div>
        </div>

      </div>
    </div>
    </>
  );
};

export default ShowCigar;
