import React, { useState, useEffect } from "react";
import { StaticImage } from "gatsby-plugin-image";
import { useTranslation } from "react-i18next";

const Footer = () => {

  const { t } = useTranslation();
  const [deferredPrompt, setDeferredPrompt] = useState(null);
  const [isInstalled, setIsInstalled] = useState(false);
  const [isStandalone, setIsStandalone] = useState(false);
  const [showScrollTop, setShowScrollTop] = useState(false);

  useEffect(() => {
    // Check if already running as standalone PWA
    if (typeof window !== "undefined" && (window.matchMedia('(display-mode: standalone)').matches || window.navigator.standalone)) {
      setIsStandalone(true);
    }

    const handler = (e) => {
      e.preventDefault();
      setDeferredPrompt(e);
    };

    window.addEventListener("beforeinstallprompt", handler);

    window.addEventListener("appinstalled", () => {
      setIsInstalled(true);
      setDeferredPrompt(null);
    });

    return () => {
      window.removeEventListener("beforeinstallprompt", handler);
    };
  }, []);

  // Show/hide scroll-to-top button based on scroll position
  useEffect(() => {
    if (typeof window === "undefined") return;
    const onScroll = () => {
      setShowScrollTop(window.scrollY > 400);
    };
    window.addEventListener("scroll", onScroll, { passive: true });
    return () => window.removeEventListener("scroll", onScroll);
  }, []);

  const scrollToTop = () => {
    if (typeof window !== "undefined") {
      document.body.style.overflow = '';  // Restaura scroll (puede estar bloqueado por age gate)
      document.documentElement.style.overflow = '';
      window.scrollTo({ top: 0, behavior: 'smooth' });
    }
  };

  const scrollToSection = (sectionId) => {
    if (typeof window === "undefined") return;
    const el = document.getElementById(sectionId);
    if (!el) return;
    document.body.style.overflow = '';  // Restaura scroll
    document.documentElement.style.overflow = '';
    el.scrollIntoView({ behavior: 'smooth', block: 'start' });
  };

  const handleInstallClick = async () => {
    if (!deferredPrompt) return;
    deferredPrompt.prompt();
    const result = await deferredPrompt.userChoice;
    if (result.outcome === "accepted") {
      setIsInstalled(true);
    }
    setDeferredPrompt(null);
  };

  // Always show the install button (not hidden even without beforeinstallprompt event yet)
  const canInstall = !isInstalled && !isStandalone;

  return (
    <>
      <footer className="bg-[#FFA800] w-screen h-auto    border-t-2 border-[#bf5512] relative    flex flex-col items-center justify-center">

        {/* Scroll-to-top button */}
        <div
          onClick={scrollToTop}
          className={`fixed bottom-6 right-6 z-[9999] w-14 h-14 rounded-full bg-[#783689] text-white shadow-2xl flex items-center justify-center cursor-pointer transition-all duration-300 hover:scale-110 hover:bg-[#9b4fb0] active:scale-95 ${
            showScrollTop
              ? 'opacity-100 translate-y-0 pointer-events-auto'
              : 'opacity-0 translate-y-4 pointer-events-none'
          }`}
          title="Ir arriba"
        >
          <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 24 24" fill="currentColor" className="w-7 h-7">
            <path fillRule="evenodd" d="M11.47 7.72a.75.75 0 0 1 1.06 0l7.5 7.5a.75.75 0 1 1-1.06 1.06L12 9.31l-6.97 6.97a.75.75 0 0 1-1.06-1.06l7.5-7.5Z" clipRule="evenodd" />
          </svg>
        </div>

    <div className= " grid   grid-cols-[2fr_2fr_1fr_1fr]   m-auto gap-4 w-full border-2 border-red-900 ">
    <div className="flex flex-col items-center justify-center gap-2 m-4 ">
      <StaticImage
        src="../../static/footer/-logo-cigar-brevas.png"
        alt="Logo Cigar Breva"
        className="w-[20rem] h-auto object-cover pointer-events-none select-none"
        placeholder="dominantColor"
        onContextMenu={(e) => e.preventDefault()}
      />
      </div>


       <div className="z-10 flex flex-col items-center justify-center gap-2 m-4 align-start">
      <StaticImage
        src="../../static/footer/-name-cigar-Brevas.png"
        alt="Logo Cigar Breva"
        className="w-[35rem] h-auto object-cover pointer-events-none select-none"
        placeholder="dominantColor"
        onContextMenu={(e) => e.preventDefault()}
      />

      <p className="text-[17px] text-center text-white font-bold">
       {t("elaboracion_mano")}
      </p>
      
       <p className="text-[0.8rem] text-center text-white font-bold">
        {t("prohibida_venta_corta")}
      </p>
        </div>
{/* // columna tres */}
<div className = "flex flex-col  items-center justify-center gap-2 mt-3 align-center">

            <div className="w-[4rem] bg-[#E5FDD3]  align-start border-radius-2xl"> 

                {/* // zone redes socials */}
                    <span className="h-[content] m-3 flex flex-col items-center gap-3">

                      {/* Telegram */}
                      <a
                        href="https://t.me/cigargamospurosbrevas"
                        target="_blank"
                        rel="noopener noreferrer"
                        className="block cursor-pointer hover:scale-110 transition-transform"
                      >
                        <StaticImage
                          src="../../static/footer/-logo-msn-telegram.webp"
                          alt="Telegram"
                          className="w-[2rem] h-auto object-cover pointer-events-none select-none m-2"
                          placeholder="dominantColor"
                          onContextMenu={(e) => e.preventDefault()}
                        />
                      </a>

                      {/* Facebook */}
                      <a
                        href="https://www.facebook.com/cigarros.brevas.9"
                        target="_blank"
                        rel="noopener noreferrer"
                        className="block cursor-pointer hover:scale-110 transition-transform"
                      >
                        <StaticImage
                          src="../../static/footer/-logo-cigar-face.webp"
                          alt="Facebook"
                          className="w-[2rem] h-auto object-cover pointer-events-none select-none m-2"
                          placeholder="dominantColor"
                          onContextMenu={(e) => e.preventDefault()}
                        />
                      </a>

                      {/* WhatsApp */}
                      <a
                        href="https://wa.me/573174044408"
                        target="_blank"
                        rel="noopener noreferrer"
                        className="block cursor-pointer hover:scale-110 transition-transform"
                      >
                        <StaticImage
                          src="../../static/footer/-logo-msn-whatup.webp"
                          alt="WhatsApp"
                          className="w-[2rem] h-auto object-cover pointer-events-none select-none m-2"
                          placeholder="dominantColor"
                          onContextMenu={(e) => e.preventDefault()}
                        />
                      </a>

                      {/* Instagram */}
                      <a
                        href="https://www.instagram.com/vitolasbrevas"
                        target="_blank"
                        rel="noopener noreferrer"
                        className="block cursor-pointer hover:scale-110 transition-transform"
                      >
                        <StaticImage
                          src="../../static/footer/-logo-insta-social.webp"
                          alt="Instagram"
                          className="w-[2rem] h-auto object-cover pointer-events-none select-none m-2"
                          placeholder="dominantColor"
                          onContextMenu={(e) => e.preventDefault()}
                        />
                      </a>

                    </span>
            </div>

            <span className="text-[12px] text-center text-white font-bold m-7 p-2">
                {t("todos_derechos")}
            </span>
</div>


            <div className="text-shadow-2xs text-[1.1rem] grid grid-cols-2 items-center justify-center gap-2">
                <div className="flex flex-col items-center justify-center gap-2 m-4 align-start">

                  {/* Bienvenidos → Welcome section */}
                  <span
                    onClick={() => scrollToSection('welcome-section')}
                    className="cursor-pointer hover:scale-110 transition-transform duration-300 hover:text-white/80 active:scale-95 select-none"
                  >
                    {t("bienvenidos")}
                  </span>

                  {/* Compras → ShowCigar section */}
                  <span
                    onClick={() => scrollToSection('compras')}
                    className="cursor-pointer hover:scale-110 transition-transform duration-300 hover:text-white/80 active:scale-95 select-none"
                  >
                    {t("compras")}
                  </span>

                  {/* Puros → CigarVitolar section */}
                  <span
                    onClick={() => scrollToSection('contactoRef_vitolar')}
                    className="cursor-pointer hover:scale-110 transition-transform duration-300 hover:text-white/80 active:scale-95 select-none"
                  >
                    {t("puros")}
                  </span>

                  {/* Idioma → top of page (LanguageSelector) */}
                  <span
                    onClick={scrollToTop}
                    className="cursor-pointer hover:scale-110 transition-transform duration-300 hover:text-white/80 active:scale-95 select-none"
                  >
                    {t("idioma")}
                  </span>

                </div>

                <div className="flex flex-col items-center justify-center gap-2 m-4 align-start">

                  <StaticImage
                    src="../../static/footer/-up-init-welcome.webp"
                    alt="Logo Cigar Breva"
                    className="w-[5rem] h-auto object-cover pointer-events-none select-none m-2"
                    placeholder="dominantColor"
                    onContextMenu={(e) => e.preventDefault()}
                  />

                </div>

            </div>

      {/* PWA Install Button - always visible */}
      {canInstall && (
        <div className="col-span-full flex justify-center py-4">
          <button
            onClick={handleInstallClick}
            className={`flex items-center gap-3 font-bold px-6 py-3 rounded-full shadow-lg transition-all duration-300 hover:scale-110 active:scale-95 ${
              deferredPrompt
                ? 'bg-[#783689] hover:bg-[#9b4fb0] text-white'
                : 'bg-[#9b7f49] hover:bg-[#b89b5e] text-white'
            }`}
            title={deferredPrompt ? 'Instalar aplicación' : 'Cargando... espera un momento'}
          >
            {/* Install icon SVG */}
            <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 24 24" fill="currentColor" className="w-6 h-6">
              <path d="M12 16.5a.75.75 0 0 1-.75-.75V5.81l-2.22 2.22a.75.75 0 0 1-1.06-1.06l3.5-3.5a.75.75 0 0 1 1.06 0l3.5 3.5a.75.75 0 0 1-1.06 1.06L12.75 5.81v9.94c0 .414-.336.75-.75.75Z" />
              <path d="M4.5 15.75a.75.75 0 0 1 .75.75v1.5a1.5 1.5 0 0 0 1.5 1.5h10.5a1.5 1.5 0 0 0 1.5-1.5v-1.5a.75.75 0 0 1 1.5 0v1.5a3 3 0 0 1-3 3H6.75a3 3 0 0 1-3-3v-1.5a.75.75 0 0 1 .75-.75Z" />
            </svg>
            <span className="text-lg">Instalar App</span>
          </button>
        </div>
      )}
</div>

      </footer>
    </>
  );
};

export default Footer;